import { useState } from "react";

function InputBox({ onSend, disabled }) {
    const [text, setText] = useState("");

    const handleSend = () => {
        if (!text.trim() || disabled) return;
        onSend(text);
        setText("");
    };

    return (
        <div
            style={{
                display: "flex",
                padding: "12px",
                borderTop: "1px solid #ddd",
                background: "white",
            }}
        >
            <input
                value={text}
                disabled={disabled}
                onChange={(e) => setText(e.target.value)}
                placeholder={disabled ? "AI is responding..." : "Type your message..."}
                style={{
                    flex: 1,
                    padding: "10px",
                    borderRadius: "8px",
                    border: "1px solid #ccc",
                }}
                onKeyDown={(e) => e.key === "Enter" && handleSend()}
            />
            <button
                onClick={handleSend}
                disabled={disabled}
                style={{
                    marginLeft: "10px",
                    padding: "10px 16px",
                    borderRadius: "8px",
                    border: "none",
                    backgroundColor: disabled ? "#9ca3af" : "#2563eb",
                    color: "white",
                }}
            >
                Send
            </button>
        </div>
    );
}

export default InputBox;
